mapper.select:
SELECT id, department_code, name, description, creator, enabled, created_at, updated_at, deleted FROM sys_department WHERE deleted = 0
AND (department_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE sys_department
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
